import Dashboard from '../assests/admin/admin/Dashboard';
import Profile from '../assests/admin/admin/Profile';

const routes =
    [
        // The route for '/admin' itself is effectively handled by the redirect in MasterLayout
        { path: 'dashboard', name: 'Dashboard', component: Dashboard }, // Path relative to /admin/*
        {path: '/admin/category', exact: true, name: 'Category', component: Profile},
        { path: 'profile', name: 'Profile', component: Profile },     // Path relative to /admin/*
    ];

export default routes;
